-- ----------------------------
-- Table structure for activity
-- ----------------------------
DROP TABLE IF EXISTS `activity`;
CREATE TABLE `activity`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '活动ID',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '活动名称',
  `cover_image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '封面图',
  `activity_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '活动类型',
  `area` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '服务区域',
  `recruit_count` int NOT NULL COMMENT '招募人数',
  `enrolled_count` int NULL DEFAULT 0 COMMENT '已报名人数',
  `estimated_hours` decimal(5, 2) NULL DEFAULT NULL COMMENT '预计时长/人',
  `reward_points` int NULL DEFAULT NULL COMMENT '奖励积分/人',
  `signup_start_time` datetime(0) NULL DEFAULT NULL COMMENT '报名开始时间',
  `signup_end_time` datetime(0) NULL DEFAULT NULL COMMENT '报名结束时间',
  `activity_start_time` datetime(0) NULL DEFAULT NULL COMMENT '活动开始时间',
  `activity_end_time` datetime(0) NULL DEFAULT NULL COMMENT '活动结束时间',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '活动详情',
  `need_audit` tinyint NULL DEFAULT 0 COMMENT '是否需要审核 1-是 0-否',
  `organizer_id` bigint NULL DEFAULT NULL COMMENT '组织者ID',
  `status` tinyint NULL DEFAULT 0 COMMENT '状态 0-草稿 1-招募中 2-进行中 3-已结束',
  `create_time` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `update_time` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 12 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '活动表' ROW_FORMAT = Dynamic;

