INSERT INTO `activity` VALUES (2, '爱心敬老院慰问活动', 'https://picsum.photos/800/500?random=1764094903378', '助老扶幼', '夕阳红敬老院', 22, 1, 4.00, 40, '2025-11-21 08:00:00', '2025-11-29 18:00:00', '2025-12-01 14:00:00', '2025-12-01 18:00:00', '用温暖陪伴老人，传递爱心！为老人表演节目、聊天、整理房间等。', 1, 2, 4, '2025-11-22 22:09:33', NULL);
