INSERT INTO `activity` VALUES (5, '社区运动会志愿服务', 'https://picsum.photos/800/500?random=1764177743584', '大型赛会', '社区体育中心', 50, 2, 5.00, 50, '2025-11-20 08:00:00', '2025-11-26 18:00:00', '2025-11-26 08:00:00', '2025-11-26 17:00:00', '大型社区运动会志愿者招募！负责现场引导、秩序维护、后勤保障等工作。', 1, 2, 3, '2025-11-22 22:09:33', NULL);
INSERT INTO `activity` VALUES (6, '义务植树活动', 'https://picsum.photos/400/300?random=6', '环境卫生', '东郊公园', 40, 2, 4.00, 40, '2025-11-23 08:00:00', '2025-12-10 18:00:00', '2025-12-12 08:00:00', '2025-12-12 12:00:00', '绿化环境，美化家园！一起种下希望的树苗。', 0, 2, 3, '2025-11-22 22:09:33', '2025-11-22 22:09:33');
