-- ----------------------------
-- Table structure for article
-- ----------------------------
DROP TABLE IF EXISTS `article`;
CREATE TABLE `article`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '资讯ID',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '标题',
  `article_type` tinyint NOT NULL COMMENT '类型 1-通知公告 2-活动风采 3-志愿者故事',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '内容',
  `cover_image` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '封面图(Base64)',
  `is_top` tinyint NULL DEFAULT 0 COMMENT '是否置顶',
  `status` tinyint NULL DEFAULT 1 COMMENT '状态',
  `publisher_id` bigint NULL DEFAULT NULL COMMENT '发布人ID',
  `create_time` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `views` int NULL DEFAULT 0 COMMENT '浏览量',
  `update_time` datetime(0) NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 11 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '资讯表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of article
-- ----------------------------
INSERT INTO `article` VALUES (1, '温暖冬日：社区敬老院慰问活动圆满结束', 2, '11月20日，我社区志愿者团队来到夕阳红敬老院，为老人们带去温暖与关怀。志愿者们为老人表演节目、陪伴聊天、整理房间，用实际行动诠释了\"老吾老以及人之老\"的传统美德。活动中，老人们脸上洋溢着幸福的笑容，纷纷表示感谢。', 'https://picsum.photos/800/500?random=21', 1, 1, 2, '2025-11-23 19:17:09', 1, NULL);
INSERT INTO `article` VALUES (2, '环保先行：社区环境卫生大扫除活动', 2, '为营造整洁优美的社区环境，我们组织了环境卫生大扫除活动。30余名志愿者积极参与，清扫街道、清理垃圾、美化环境。经过3小时的努力，社区面貌焕然一新。', 'https://picsum.photos/800/500?random=22', 0, 1, 2, '2025-11-23 19:17:09', 0, NULL);
INSERT INTO `article` VALUES (3, '爱心传递：志愿者王小明的感人故事', 3, '王小明是我社区的五星级志愿者，累计服务时长超过500小时。他说：\"帮助别人让我感到快乐和充实，这是金钱买不到的幸福。\"让我们一起为这样的志愿者点赞！', 'https://picsum.photos/800/500?random=23', 1, 1, 2, '2025-11-23 19:17:09', 1, NULL);
INSERT INTO `article` VALUES (4, '知识改变命运：义务支教活动持续进行', 2, '我们的志愿者每周三晚上都会前往希望小学开展义务支教活动，为孩子们辅导功课、开展兴趣课程。孩子们的笑脸是我们最大的动力！', 'https://picsum.photos/800/500?random=24', 0, 1, 2, '2025-11-23 19:17:09', 0, NULL);
INSERT INTO `article` VALUES (5, '十年坚守：致敬最美志愿者李大妈', 3, '李大妈今年70岁，坚持做志愿服务已有10年。她说：\"只要身体允许，我会一直做下去。\"她的事迹感动了无数人，是我们学习的榜样。', 'https://picsum.photos/800/500?random=25', 0, 1, 2, '2025-11-23 19:17:09', 0, NULL);
INSERT INTO `article` VALUES (6, '社区运动会圆满落幕，志愿者服务获好评', 2, '在刚刚结束的社区运动会上，50名志愿者提供了全程服务保障。从现场引导到后勤保障，志愿者们用专业的服务赢得了居民的一致好评。', 'https://picsum.photos/800/500?random=26', 0, 1, 2, '2025-11-23 19:17:09', 0, NULL);
INSERT INTO `article` VALUES (7, '图书整理志愿服务：让知识有序传播', 2, '志愿者们在社区图书馆开展图书整理活动，分类、编号、上架，让每一本书都能找到它的归宿。阅读从整理开始，知识从这里传播。', 'https://picsum.photos/800/500?random=27', 0, 1, 2, '2025-11-23 19:17:09', 0, NULL);
INSERT INTO `article` VALUES (8, '用镜头记录美好：摄影志愿者张伟的故事', 3, '志愿者张伟用相机记录下每一次志愿活动的精彩瞬间。他说：\"我希望通过照片，让更多人了解志愿服务，加入我们的行列。\"', 'https://picsum.photos/800/500?random=28', 0, 1, 2, '2025-11-23 19:17:09', 0, NULL);
INSERT INTO `article` VALUES (11, '测试', 2, '111', 'data:image/jpeg;base64,', 1, 1, NULL, '2025-11-27 03:34:27', 3, '2025-11-27 03:34:27');

-- ----------------------------
-- Table structure for enrollment
-- ----------------------------
DROP TABLE IF EXISTS `enrollment`;
CREATE TABLE `enrollment`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '报名ID',
  `activity_id` bigint NOT NULL COMMENT '活动ID',
  `volunteer_id` bigint NOT NULL COMMENT '志愿者ID',
  `audit_status` tinyint NULL DEFAULT 0 COMMENT '审核状态 0-待审核 1-通过 2-拒绝',
  `audit_remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '审核备注',
  `sign_in_time` datetime(0) NULL DEFAULT NULL COMMENT '签到时间',
  `sign_out_time` datetime(0) NULL DEFAULT NULL COMMENT '签退时间',
  `actual_hours` decimal(5, 2) NULL DEFAULT NULL COMMENT '实际时长',
  `reward_status` tinyint NULL DEFAULT 0 COMMENT '奖励发放状态 0-未发放 1-已发放',
  `create_time` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `update_time` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 22 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '活动报名表' ROW_FORMAT = Dynamic;

