  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `volunteer_id` bigint NOT NULL COMMENT '志愿者ID',
  `activity_id` bigint NULL DEFAULT NULL COMMENT '关联活动ID',
  `service_hours` decimal(5, 2) NOT NULL COMMENT '服务时长',
  `service_date` date NOT NULL COMMENT '服务日期',
  `record_type` tinyint NULL DEFAULT 1 COMMENT '记录类型 1-系统发放 2-补录',
  `audit_status` tinyint NULL DEFAULT 1 COMMENT '审核状态 1-已通过 0-待审核 2-已拒绝',
  `auditor` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '认定人',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  `create_time` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `balance_snapshot` int NULL DEFAULT 0 COMMENT '变动后的余额快照',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 14 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '时长记录表' ROW_FORMAT = Dynamic;

